  8→    <link rel="canonical" href="{{ canonical_url }}">
  9→
 10→    {%- if settings.favicon != blank -%}
 11→      <link rel="icon" type="image/png" href="{{ settings.favicon | image_url: width: 32, height: 32 }}">
 12→    {%- endif -%}
 13→
 14→    {%- unless settings.type_header_font.system? and settings.type_body_font.system? -%}
 15→      <link rel="preconnect" href="https://fonts.shopifycdn.com" crossorigin>
 16→    {%- endunless -%}
 17→
 18→    <title>
 19→      {{ page_title }}
 20→      {%- if current_tags %} &ndash; tagged "{{ current_tags | join: ', ' }}"{% endif -%}
 21→      {%- if current_page != 1 %} &ndash; Page {{ current_page }}{% endif -%}
 22→      {%- unless page_title contains shop.name %} &ndash; {{ shop.name }}{% endunless -%}
 23→    </title>
 24→
 25→    {% if page_description %}
 26→      <meta name="description" content="{{ page_description | escape }}">
 27→    {% endif %}
 28→
 29→    {% render 'meta-tags' %}
 30→
 31→    <script src="{{ 'constants.js' | asset_url }}" defer="defer"></script>
 32→    <script src="{{ 'pubsub.js' | asset_url }}" defer="defer"></script>
 33→    <script src="{{ 'global.js' | asset_url }}" defer="defer"></script>
 34→    <script src="{{ 'details-disclosure.js' | asset_url }}" defer="defer"></script>
 35→    <script src="{{ 'details-modal.js' | asset_url }}" defer="defer"></script>
 36→    <script src="{{ 'search-form.js' | asset_url }}" defer="defer"></script>
 37→
 38→    {%- if settings.animations_reveal_on_scroll -%}
 39→      <script src="{{ 'animations.js' | asset_url }}" defer="defer"></script>
 40→    {%- endif -%}
 41→
 42→    {{ content_for_header }}
 43→
 44→    {%- liquid
 45→      assign body_font_bold = settings.type_body_font | font_modify: 'weight', 'bold'
 46→      assign body_font_italic = settings.type_body_font | font_modify: 'style', 'italic'
 47→      assign body_font_bold_italic = body_font_bold | font_modify: 'style', 'italic'
 48→    %}
 49→
 50→    {% style %}
 51→      {{ settings.type_body_font | font_face: font_display: 'swap' }}
 52→      {{ body_font_bold | font_face: font_display: 'swap' }}
 53→      {{ body_font_italic | font_face: font_display: 'swap' }}
 54→      {{ body_font_bold_italic | font_face: font_display: 'swap' }}
 55→      {{ settings.type_header_font | font_face: font_display: 'swap' }}
 56→
 57→      {% for scheme in settings.color_schemes -%}
 58→        {% assign scheme_classes = scheme_classes | append: ', .color-' | append: scheme.id %}
 59→        {% if forloop.index == 1 -%}
 60→          :root,
 61→        {%- endif %}
 62→        .color-{{ scheme.id }} {
 63→          --color-background: {{ scheme.settings.background.red }},{{ scheme.settings.background.green }},{{ scheme.settings.background.blue }};
 64→        {% if scheme.settings.background_gradient != empty %}
 65→          --gradient-background: {{ scheme.settings.background_gradient }};
 66→        {% else %}
 67→          --gradient-background: {{ scheme.settings.background }};
 68→        {% endif %}
 69→
 70→        {% liquid
 71→          assign background_color = scheme.settings.background
 72→          assign background_color_brightness = background_color | color_brightness
 73→          if background_color_brightness <= 26
 74→            assign background_color_contrast = background_color | color_lighten: 50
 75→          elsif background_color_brightness <= 65
 76→            assign background_color_contrast = background_color | color_lighten: 5
 77→          else
 78→            assign background_color_contrast = background_color | color_darken: 25
 79→          endif
 80→        %}
 81→
 82→        --color-foreground: {{ scheme.settings.text.red }},{{ scheme.settings.text.green }},{{ scheme.settings.text.blue }};
 83→        --color-background-contrast: {{ background_color_contrast.red }},{{ background_color_contrast.green }},{{ background_color_contrast.blue }};
 84→        --color-shadow: {{ scheme.settings.shadow.red }},{{ scheme.settings.shadow.green }},{{ scheme.settings.shadow.blue }};
 85→        --color-button: {{ scheme.settings.button.red }},{{ scheme.settings.button.green }},{{ scheme.settings.button.blue }};
 86→        --color-button-text: {{ scheme.settings.button_label.red }},{{ scheme.settings.button_label.green }},{{ scheme.settings.button_label.blue }};
 87→        --color-secondary-button: {{ scheme.settings.background.red }},{{ scheme.settings.background.green }},{{ scheme.settings.background.blue }};
 88→        --color-secondary-button-text: {{ scheme.settings.secondary_button_label.red }},{{ scheme.settings.secondary_button_label.green }},{{ scheme.settings.secondary_button_label.blue }};
 89→        --color-link: {{ scheme.settings.secondary_button_label.red }},{{ scheme.settings.secondary_button_label.green }},{{ scheme.settings.secondary_button_label.blue }};
 90→        --color-badge-foreground: {{ scheme.settings.text.red }},{{ scheme.settings.text.green }},{{ scheme.settings.text.blue }};
 91→        --color-badge-background: {{ scheme.settings.background.red }},{{ scheme.settings.background.green }},{{ scheme.settings.background.blue }};
 92→        --color-badge-border: {{ scheme.settings.text.red }},{{ scheme.settings.text.green }},{{ scheme.settings.text.blue }};
 93→        --payment-terms-background-color: rgb({{ scheme.settings.background.rgb }});
 94→      }
 95→      {% endfor %}
 96→
 97→      {{ scheme_classes | prepend: 'body' }} {
 98→        color: rgba(var(--color-foreground), 0.75);
 99→        background-color: rgb(var(--color-background));
100→      }
