122→        --media-shadow-blur-radius: {{ settings.media_shadow_blur }}px;
123→        --media-shadow-visible: {% if settings.media_shadow_opacity > 0 %}1{% else %}0{% endif %};
124→
125→        --page-width: {{ settings.page_width | divided_by: 10 }}rem;
126→        --page-width-margin: {% if settings.page_width == '1600' %}2{% else %}0{% endif %}rem;
127→
128→        --product-card-image-padding: {{ settings.card_image_padding | divided_by: 10.0 }}rem;
