132→        --product-card-border-opacity: {{ settings.card_border_opacity | divided_by: 100.0 }};
133→        --product-card-shadow-opacity: {{ settings.card_shadow_opacity | divided_by: 100.0 }};
134→        --product-card-shadow-visible: {% if settings.card_shadow_opacity > 0 %}1{% else %}0{% endif %};
135→        --product-card-shadow-horizontal-offset: {{ settings.card_shadow_horizontal_offset | divided_by: 10.0 }}rem;
136→        --product-card-shadow-vertical-offset: {{ settings.card_shadow_vertical_offset | divided_by: 10.0 }}rem;
137→        --product-card-shadow-blur-radius: {{ settings.card_shadow_blur | divided_by: 10.0 }}rem;
138→
139→        --collection-card-image-padding: {{ settings.collection_card_image_padding | divided_by: 10.0 }}rem;
