141→        --collection-card-text-alignment: {{ settings.collection_card_text_alignment }};
142→        --collection-card-border-width: {{ settings.collection_card_border_thickness | divided_by: 10.0 }}rem;
143→        --collection-card-border-opacity: {{ settings.collection_card_border_opacity | divided_by: 100.0 }};
144→        --collection-card-shadow-opacity: {{ settings.collection_card_shadow_opacity | divided_by: 100.0 }};
145→        --collection-card-shadow-visible: {% if settings.collection_card_shadow_opacity > 0 %}1{% else %}0{% endif %};
146→        --collection-card-shadow-horizontal-offset: {{ settings.collection_card_shadow_horizontal_offset | divided_by: 10.0 }}rem;
147→        --collection-card-shadow-vertical-offset: {{ settings.collection_card_shadow_vertical_offset | divided_by: 10.0 }}rem;
