            "step_number": "1",
            "title": "Choose Your Service",
            "description": "Browse our range of property services and select what you need.",
            "icon": "check-circle"
          }
        },
        "step_2": {
          "type": "step",
          "settings": {
            "step_number": "2",
            "title": "Provide Property Details",
            "description": "Enter your property address and any specific requirements.",
            "icon": "house-search"
          }
        },
        "step_3": {
          "type": "step",
          "settings": {
            "step_number": "3",
            "title": "Expert Processing",
            "description": "Our team of professionals handles your service with care.",
            "icon": "document"
          }
        },
        "step_4": {
          "type": "step",
          "settings": {
            "step_number": "4",
            "title": "Receive Your Documents",
            "description": "Get your completed documents delivered to your account.",
            "icon": "scroll"
          }
        }
      },
      "block_order": ["step_1", "step_2", "step_3", "step_4"],
      "settings": {
        "heading": "How It Works",
        "subheading": "Getting started is simple — just four easy steps",
        "color_scheme": "scheme-2",
        "padding_top": 60,
        "padding_bottom": 60
      }
    },
    "cta_banner": {
      "type": "image-banner",
      "blocks": {
        "heading": {
          "type": "heading",
          "settings": {
            "heading": "Ready to Get Started?",
            "heading_size": "h1"
          }
        },
        "text": {
          "type": "text",
          "settings": {
            "text": "Browse our full range of property services or get in touch for a free consultation.",
            "text_style": "body"
          }
        },
        "button": {
          "type": "buttons",
          "settings": {
            "button_label_1": "View All Services",
            "button_link_1": "shopify://collections/all",
            "button_style_secondary_1": false,
            "button_label_2": "Contact Us",
            "button_link_2": "",
            "button_style_secondary_2": true
          }
        }
      },
      "block_order": ["heading", "text", "button"],
      "settings": {
        "image_overlay_opacity": 50,
        "image_height": "medium",
        "desktop_content_position": "middle-center",
        "show_text_box": false,
        "desktop_content_alignment": "center",
        "color_scheme": "scheme-3",
        "mobile_content_alignment": "center",
        "stack_images_on_mobile": false,
        "show_text_below": false
      }
    }
  },
  "order": [
    "hero_banner",
    "trust_bar",
    "service_grid",
    "process_timeline",
    "cta_banner"
  ]
}

