  }

  @media screen and (max-width: 989px) {
    .service-grid__grid {
      grid-template-columns: repeat(2, 1fr);
    }

    .service-grid__heading {
      font-size: 2rem;
    }
  }

  @media screen and (max-width: 749px) {
    .service-grid {
      padding: 3rem 0;
    }

    .service-grid__grid {
      grid-template-columns: 1fr;
    }

    .service-grid__heading {
      font-size: 1.75rem;
    }
  }
</style>

{% schema %}
{
  "name": "Service Grid",
  "tag": "section",
  "class": "section-service-grid",
  "settings": [
    {
      "type": "text",
      "id": "heading",
      "label": "Heading",
      "default": "Our Services"
    },
    {
      "type": "textarea",
      "id": "subheading",
      "label": "Subheading",
      "default": "Comprehensive property services tailored for landlords, sellers, and property professionals across the UK."
    },
    {
      "type": "color",
      "id": "background_color",
      "label": "Background colour",
      "default": "#F5F0E1"
    }
  ],
  "blocks": [
    {
      "type": "service",
      "name": "Service",
      "limit": 12,
      "settings": [
        {
          "type": "text",
          "id": "title",
          "label": "Service title",
          "default": "Service Title"
        },
        {
          "type": "textarea",
          "id": "description",
          "label": "Service description",
          "default": "A short description of this property service."
        },
        {
          "type": "text",
          "id": "price_from",
          "label": "Price text",
          "default": "From £299"
        },
        {
          "type": "select",
          "id": "icon_name",
          "label": "Icon",
          "default": "document",
          "options": [
            { "value": "document", "label": "Document (Legal)" },
            { "value": "house-search", "label": "House Search (Survey)" },
            { "value": "coins", "label": "Coins (Outlays)" },
            { "value": "camera", "label": "Camera (Photography)" },
            { "value": "scroll", "label": "Scroll (Title)" },
            { "value": "arrow-up", "label": "Arrow Up (Rent Increase)" },
            { "value": "handshake", "label": "Handshake (Tenancy)" },
            { "value": "megaphone", "label": "Megaphone (Portal Boosting)" }
          ]
        },
        {
          "type": "url",
          "id": "link",
          "label": "Service link"
        }
      ]
    }
  ],
  "presets": [
    {
      "name": "Service Grid",
      "blocks": [
        {
          "type": "service",
          "settings": {
            "title": "Auction Legal Pack",
            "description": "Complete legal documentation pack required for selling your property at auction, including title deeds, local authority searches, and property information forms.",
            "price_from": "From £299",
            "icon_name": "document"
          }
        },
        {
          "type": "service",
          "settings": {
            "title": "RICS Level 2 Survey",
            "description": "Comprehensive RICS HomeBuyer Report covering the condition of the property, identifying any significant issues, defects, and urgent repairs needed.",
            "price_from": "From £399",
            "icon_name": "house-search"
          }
        },
        {
          "type": "service",
          "settings": {
            "title": "Outlays",
            "description": "We cover upfront disbursement costs including local authority searches, environmental searches, and Land Registry fees on your behalf.",
            "price_from": "From £199",
            "icon_name": "coins"
          }
        },
        {
          "type": "service",
          "settings": {
            "title": "Professional Photography",
            "description": "High-quality property photography by experienced professionals, including wide-angle interior shots, exterior images, and aerial drone photography.",
            "price_from": "From £149",
            "icon_name": "camera"
          }
        },
        {
          "type": "service",
          "settings": {
            "title": "Property Title",
            "description": "Obtain official Land Registry title documents for your property, including title register, title plan, and any associated charges or restrictions.",
            "price_from": "From £29",
            "icon_name": "scroll"
          }
        },
        {
          "type": "service",
          "settings": {
            "title": "Rent Increase",
            "description": "Professional Section 13 rent increase notice preparation and service, ensuring full compliance with current UK tenancy legislation.",
            "price_from": "From £49",
            "icon_name": "arrow-up"
          }
        },
        {
          "type": "service",
          "settings": {
            "title": "Tenancy Agreement",
            "description": "Professionally drafted assured shorthold tenancy agreements tailored to your property and circumstances, fully compliant with UK housing law.",
            "price_from": "From £79",
            "icon_name": "handshake"
          }
        },
        {
          "type": "service",
          "settings": {
            "title": "Portal Boosting",
            "description": "Maximise your property listing visibility on Rightmove, Zoopla, and OnTheMarket with premium placement and featured listing upgrades.",
            "price_from": "From £99",
            "icon_name": "megaphone"
          }
        }
      ]
    }
  ]
}
{% endschema %}

