content.content:
  1→/* ==========================================================================
  2→   Buy Property Services - Custom Stylesheet
  3→   Clean, professional styling built on Dawn defaults
  4→   ========================================================================== */
  5→@import url('https://fonts.googleapis.com/css2?family=Poppins:wght@400;500;600;700&display=swap');
  6→
  7→/* --- Custom Properties --- */
  8→:root {
  9→  --bp-green: #1A4D2E;
 10→  --bp-green-light: #2D7A4A;
 11→  --bp-orange: #E8922A;
 12→  --bp-orange-hover: #D4872E;
 13→  --bp-olive: #8FB339;
 14→  --bp-cream: #F5F0E1;
 15→  --bp-tan: #C4B699;
 16→  --bp-text: #1A1A1A;
 17→  --bp-text-light: #555555;
 18→  --bp-white: #FFFFFF;
 19→  --bp-border: #E5E5E5;
 20→}
 21→
 22→/* --- Typography --- */
 23→body, h1, h2, h3, h4, h5, h6 {
 24→  font-family: 'Poppins', -apple-system, BlinkMacSystemFont, 'Segoe UI', Roboto, sans-serif;
 25→}
 26→body {
 27→  color: var(--bp-text);
 28→  -webkit-font-smoothing: antialiased;
 29→}
 30→h1, h2, h3, h4, h5, h6 {
 31→  color: var(--bp-text);
 32→  font-weight: 700;
 33→  line-height: 1.2;
 34→}
 35→a { transition: color 0.3s ease; }
 36→
 37→/* --- Header --- */
 38→.section-header,
 39→.bps-header {
 40→  background-color: var(--bp-green);
 41→  position: sticky;
 42→  top: 0;
 43→  z-index: 1000;
 44→}
 45→.section-header a,
 46→.section-header .header__heading-link,
 47→.section-header .header__menu-item,
 48→.section-header .list-menu__item--link,
 49→.bps-header a {
 50→  color: var(--bp-white);
 51→  text-decoration: none;
 52→}
 53→.section-header .header__menu-item:hover,
 54→.section-header .list-menu__item--link:hover,
 55→.bps-header a:hover {
 56→  color: var(--bp-orange);
 57→}
 58→.section-header .header__icon,
 59→.section-header .header__icon .icon {
 60→  color: var(--bp-white);
 61→  fill: var(--bp-white);
 62→}
 63→.section-header .header__icon:hover { color: var(--bp-orange); }
 64→.section-header .cart-count-bubble {
 65→  background-color: var(--bp-orange);
 66→  color: var(--bp-white);
 67→}
 68→
 69→/* Mobile menu */
 70→.menu-drawer {
 71→  background-color: var(--bp-green);
 72→  color: var(--bp-white);
 73→}
 74→.menu-drawer a,
 75→.menu-drawer .menu-drawer__menu-item {
 76→  color: var(--bp-white);
 77→  font-family: 'Poppins', sans-serif;
 78→}
 79→.menu-drawer a:hover { color: var(--bp-orange); }
 80→.menu-drawer__close-button .icon { color: var(--bp-white); }
 81→
 82→/* --- Hero Banner --- */
 83→.hero-banner {
 84→  position: relative;
 85→  width: 100%;
 86→  min-height: 480px;
 87→  display: flex;
 88→  align-items: center;
 89→  justify-content: center;
 90→  text-align: center;
 91→  overflow: hidden;
 92→  background-size: cover;
 93→  background-position: center;
 94→}
 95→.hero-banner::after {
 96→  content: '';
 97→  position: absolute;
 98→  inset: 0;
 99→  background: linear-gradient(to top, rgba(0,0,0,0.6) 0%, rgba(0,0,0,0.3) 50%, rgba(0,0,0,0.15) 100%);
100→  z-index: 1;
101→}
102→.hero-banner__content {
103→  position: relative;
104→  z-index: 2;
105→  max-width: 720px;
106→  padding: 2rem 1.5rem;
107→}
108→.hero-banner__heading {
109→  font-size: clamp(1.75rem, 5vw, 3.25rem);
110→  font-weight: 700;
111→  color: var(--bp-white);
112→  margin-bottom: 1rem;
113→  line-height: 1.15;
114→}
115→.hero-banner__subheading {
116→  font-size: clamp(0.95rem, 2vw, 1.2rem);
117→  color: rgba(255, 255, 255, 0.9);
118→  font-weight: 400;
119→  margin-bottom: 2rem;
120→}
121→.hero-banner__actions {
122→  display: flex;
123→  gap: 1rem;
124→  justify-content: center;
125→  flex-wrap: wrap;
126→}
127→.hero-banner__trust {
128→  display: flex;
129→  gap: 2rem;
130→  justify-content: center;
131→  flex-wrap: wrap;
132→  margin-top: 2.5rem;
133→  color: rgba(255, 255, 255, 0.85);
134→  font-size: 0.9rem;
135→}
136→@media (min-width: 990px) {
137→  .hero-banner { min-height: 600px; }
138→}
139→
140→/* --- Buttons --- */
141→.btn-primary, .btn-secondary, .btn-outline-white {
142→  display: inline-flex;
143→  align-items: center;
144→  justify-content: center;
145→  font-family: 'Poppins', sans-serif;
146→  font-size: 0.95rem;
147→  font-weight: 600;
148→  padding: 0 1.75rem;
149→  height: 54px;
150→  border: none;
151→  border-radius: 12px;
152→  cursor: pointer;
153→  text-decoration: none;
154→  transition: background-color 0.3s ease, color 0.3s ease;
155→}
156→.btn-primary { background-color: var(--bp-orange); color: var(--bp-white); }
157→.btn-primary:hover { background-color: var(--bp-orange-hover); color: var(--bp-white); }
158→.btn-secondary {
159→  background-color: transparent;
160→  color: var(--bp-green);
161→  border: 2px solid var(--bp-green);
162→}
163→.btn-secondary:hover { background-color: var(--bp-green); color: var(--bp-white); }
164→.btn-outline-white {
165→  background-color: transparent;
166→  color: var(--bp-white);
167→  border: 2px solid var(--bp-white);
168→}
169→.btn-outline-white:hover { background-color: var(--bp-white); color: var(--bp-green); }
170→
171→/* Dawn button override */
172→.product-form__submit.button {
173→  background-color: var(--bp-orange);
174→  color: var(--bp-white);
175→  font-family: 'Poppins', sans-serif;
176→  font-weight: 600;
177→  border-radius: 12px;
178→  min-height: 54px;
179→}
180→.product-form__submit.button:hover {
181→  background-color: var(--bp-orange-hover);
182→}
183→
184→/* --- Service Grid --- */
185→.service-grid {
186→  display: grid;
187→  grid-template-columns: 1fr;
188→  gap: 1.5rem;
189→}
190→.service-grid__card {
191→  background: var(--bp-white);
192→  border: 1px solid var(--bp-border);
193→  border-radius: 12px;
194→  padding: 2rem 1.5rem;
195→  text-align: center;
196→  box-shadow: 0 2px 8px rgba(0, 0, 0, 0.08);
197→  transition: transform 0.3s ease, box-shadow 0.3s ease;
198→}
199→.service-grid__card:hover {
200→  transform: translateY(-4px);
201→  box-shadow: 0 8px 24px rgba(0, 0, 0, 0.12);
202→}
203→.service-grid__icon {
204→  width: 64px;
205→  height: 64px;
206→  margin: 0 auto 1rem;
207→  display: flex;
208→  align-items: center;
209→  justify-content: center;
210→  background-color: rgba(26, 77, 46, 0.08);
211→  border-radius: 50%;
212→}
213→.service-grid__icon img,
214→.service-grid__icon svg { width: 32px; height: 32px; }
215→.service-grid__title {
216→  font-size: 1.125rem;
217→  font-weight: 600;
218→  color: var(--bp-text);
219→  margin-bottom: 0.5rem;
220→}
221→.service-grid__desc {
222→  font-size: 0.9rem;
223→  color: var(--bp-text-light);
224→  line-height: 1.6;
225→  margin-bottom: 1rem;
226→}
227→.service-grid__price {
228→  font-size: 1.35rem;
229→  font-weight: 700;
230→  color: var(--bp-orange);
231→  margin-bottom: 1.25rem;
232→}
233→.service-grid__price small { font-size: 0.85rem; font-weight: 400; color: var(--bp-text-light); }
234→.service-grid__link { color: var(--bp-green); font-weight: 600; font-size: 0.9rem; text-decoration: none; }
235→.service-grid__link:hover { color: var(--bp-green-light); }
236→
237→@media (min-width: 750px) {
238→  .service-grid { grid-template-columns: repeat(2, 1fr); }
239→}
240→@media (min-width: 990px) {
241→  .service-grid { grid-template-columns: repeat(3, 1fr); gap: 2rem; }
242→}
243→
244→/* --- Trust Bar --- */
245→.trust-bar {
246→  background-color: var(--bp-cream);
247→  display: flex;
248→  justify-content: center;
249→  gap: 3rem;
250→  flex-wrap: wrap;
251→  padding: 3rem 1.5rem;
252→}
253→.trust-bar__item { text-align: center; }
254→.trust-bar__stat {
255→  font-size: 2rem;
256→  font-weight: 700;
257→  color: var(--bp-green);
258→  line-height: 1;
259→  margin-bottom: 0.35rem;
260→}
261→.trust-bar__label { font-size: 0.85rem; color: var(--bp-text-light); }
262→@media (max-width: 749px) {
263→  .trust-bar {
264→    display: grid;
265→    grid-template-columns: repeat(2, 1fr);
266→    gap: 1.5rem;
267→  }
268→}
269→
270→/* --- Process Timeline --- */
271→.process-timeline {
272→  position: relative;
273→  display: flex;
274→  flex-direction: column;
275→  gap: 2rem;
276→  padding-left: 2.5rem;
277→}
278→.process-timeline::before {
279→  content: '';
280→  position: absolute;
281→  left: 15px;
282→  top: 0;
283→  bottom: 0;
284→  width: 2px;
285→  background-color: var(--bp-border);
286→}
287→.process-timeline__step { position: relative; }
288→.process-timeline__number {
289→  position: absolute;
290→  left: -2.5rem;
291→  top: 0;
292→  width: 32px;
293→  height: 32px;
294→  background-color: var(--bp-green);
295→  color: var(--bp-white);
296→  border-radius: 50%;
297→  display: flex;
298→  align-items: center;
299→  justify-content: center;
300→  font-size: 0.85rem;
301→  font-weight: 700;
302→  z-index: 1;
303→}
304→.process-timeline__title { font-size: 1rem; font-weight: 600; color: var(--bp-text); margin-bottom: 0.25rem; }
305→.process-timeline__desc { font-size: 0.875rem; color: var(--bp-text-light); line-height: 1.5; }
306→@media (min-width: 990px) {
307→  .process-timeline {
308→    flex-direction: row;
309→    padding-left: 0;
310→    gap: 0;
311→    justify-content: space-between;
312→  }
313→  .process-timeline::before {
314→    left: 0; right: 0;
315→    top: 15px; bottom: auto;
316→    width: auto; height: 2px;
317→  }
318→  .process-timeline__step {
319→    flex: 1;
320→    text-align: center;
321→    padding: 3rem 1rem 0;
322→  }
323→  .process-timeline__number {
324→    left: 50%;
325→    top: 0;
326→    transform: translateX(-50%);
327→  }
328→}
329→
330→/* --- Product / Service Page --- */
331→.bps-accordion {
332→  border: 1px solid var(--bp-border);
333→  border-radius: 8px;
334→  overflow: hidden;
335→  margin-bottom: 0.75rem;
336→}
337→.bps-accordion summary,
338→.bps-accordion__trigger {
339→  width: 100%;
340→  display: flex;
341→  align-items: center;
342→  justify-content: space-between;
343→  background: var(--bp-white);
344→  border: none;
345→  padding: 1rem 1.25rem;
346→  font-family: 'Poppins', sans-serif;
347→  font-size: 1rem;
348→  font-weight: 600;
349→  color: var(--bp-text);
350→  cursor: pointer;
351→}
352→.bps-accordion summary:hover,
353→.bps-accordion__trigger:hover {
354→  background-color: rgba(245, 240, 225, 0.5);
355→}
356→.bps-accordion__content {
357→  padding: 1rem 1.25rem;
358→  font-size: 0.9rem;
359→  line-height: 1.65;
360→  color: var(--bp-text);
361→  background: var(--bp-white);
362→}
363→
364→/* Property address input */
365→.bps-address-input {
