/* ==========================================================================
   Buy Property Services — Custom Theme Styles
   Clean, professional. Works with Dawn defaults.
   ========================================================================== */
@import url('https://fonts.googleapis.com/css2?family=Poppins:wght@400;500;600;700&display=swap');

/* --- Brand Variables --- */
:root {
  --bp-green: #1A4D2E;
  --bp-green-light: #2D7A4A;
  --bp-orange: #E8922A;
  --bp-orange-hover: #D4872E;
  --bp-olive: #8FB339;
  --bp-cream: #F5F0E1;
  --bp-tan: #C4B699;
  --bp-text: #1A1A1A;
  --bp-text-light: #555555;
  --bp-white: #FFFFFF;
  --bp-border: #E5E5E5;
}

/* --- Typography --- */
body,
h1, h2, h3, h4, h5, h6 {
  font-family: 'Poppins', -apple-system, BlinkMacSystemFont, 'Segoe UI', Roboto, sans-serif;
}
body {
  color: var(--bp-text);
  -webkit-font-smoothing: antialiased;
}
h1, h2, h3, h4, h5, h6 {
  color: var(--bp-text);
  font-weight: 700;
  line-height: 1.2;
}

/* --- Header (Dawn overrides) --- */
.section-header {
  background-color: var(--bp-green) !important;
}
.section-header .color-scheme-1 {
  background-color: var(--bp-green);
}
.header-wrapper {
  background-color: var(--bp-green) !important;
}
.section-header a,
.section-header .header__heading-link,
.section-header .header__menu-item,
.section-header .list-menu__item--link {
  color: var(--bp-white) !important;
  text-decoration: none;
}
.section-header .header__menu-item:hover,
.section-header .list-menu__item--link:hover {
  color: var(--bp-orange) !important;
}
.section-header .header__icon,
.section-header .header__icon .icon {
  color: var(--bp-white) !important;
  fill: var(--bp-white);
}
.section-header .header__icon:hover,
.section-header .header__icon:hover .icon {
  color: var(--bp-orange) !important;
}
.section-header .cart-count-bubble {
  background-color: var(--bp-orange);
  color: var(--bp-white);
}

/* Mobile menu drawer */
.menu-drawer {
  background-color: var(--bp-green) !important;
}
.menu-drawer a,
.menu-drawer .menu-drawer__menu-item {
  color: var(--bp-white) !important;
  font-family: 'Poppins', sans-serif;
}
.menu-drawer a:hover {
  color: var(--bp-orange) !important;
}
.menu-drawer__close-button .icon {
  color: var(--bp-white);
}
.header__inline-menu .header__menu-item {
  color: var(--bp-white);
}

/* --- Hero Banner --- */
.hero-banner {
  position: relative;
  width: 100%;
  min-height: 500px;
  display: flex;
  align-items: center;
  justify-content: center;
  text-align: center;
  overflow: hidden;
}

.hero-banner__media {
  position: absolute;
  inset: 0;
  z-index: 0;
}

.hero-banner__image {
  width: 100%;
  height: 100%;
  object-fit: cover;
  display: block;
}

.hero-banner__placeholder {
  width: 100%;
  height: 100%;
  background: linear-gradient(135deg, var(--bp-green) 0%, #2D7A4A 100%);
}

.hero-banner__overlay {
  position: absolute;
  inset: 0;
}

.hero-banner__content {
  position: relative;
  z-index: 2;
  max-width: 720px;
  padding: 3rem 1.5rem;
}

.hero-banner__heading {
  font-size: clamp(1.75rem, 5vw, 3.25rem);
  font-weight: 700;
  color: var(--bp-white);
  margin: 0 0 1rem;
  line-height: 1.15;
  text-shadow: 0 2px 8px rgba(0, 0, 0, 0.3);
}

.hero-banner__subheading {
  font-size: clamp(0.95rem, 2vw, 1.15rem);
  color: rgba(255, 255, 255, 0.9);
  font-weight: 400;
  margin: 0 0 2rem;
  line-height: 1.6;
}

.hero-banner__buttons {
  display: flex;
  gap: 1rem;
  justify-content: center;
  flex-wrap: wrap;
}

.hero-banner__btn {
  display: inline-flex;
  align-items: center;
  justify-content: center;
  font-family: 'Poppins', sans-serif;
  font-size: 0.95rem;
  font-weight: 600;
  padding: 0 2rem;
  height: 54px;
  border-radius: 12px;
  cursor: pointer;
  text-decoration: none;
  transition: all 0.3s ease;
}

.hero-banner__btn--primary {
  background-color: var(--bp-orange);
  color: var(--bp-white);
  border: none;
}
.hero-banner__btn--primary:hover {
  background-color: var(--bp-orange-hover);
  color: var(--bp-white);
}

.hero-banner__btn--secondary {
  background-color: transparent;
  color: var(--bp-white);
  border: 2px solid var(--bp-white);
}
.hero-banner__btn--secondary:hover {
  background-color: var(--bp-white);
  color: var(--bp-green);
}

.hero-banner__trust-bar {
  position: absolute;
  bottom: 0;
  left: 0;
  right: 0;
  z-index: 2;
  background: rgba(0, 0, 0, 0.25);
  padding: 0.75rem 0;
}

.hero-banner__trust-row {
  display: flex;
  justify-content: center;
  gap: 2rem;
  flex-wrap: wrap;
}

.hero-banner__trust-item {
  color: rgba(255, 255, 255, 0.9);
  font-size: 0.85rem;
  font-weight: 500;
}

@media (min-width: 990px) {
  .hero-banner {
    min-height: 600px;
  }
}

@media (max-width: 749px) {
  .hero-banner {
    min-height: 420px;
  }
  .hero-banner__buttons {
    flex-direction: column;
    align-items: center;
  }
  .hero-banner__btn {
    width: 100%;
    max-width: 280px;
  }
  .hero-banner__trust-row {
    gap: 1rem;
  }
  .hero-banner__trust-item {
    font-size: 0.75rem;
  }
}

/* --- Trust Bar --- */
.trust-bar {
  background-color: var(--bp-cream);
}

.trust-bar__heading {
  font-size: 1.1rem;
  font-weight: 600;
  text-align: center;
  color: var(--bp-text);
  margin: 0 0 1.5rem;
}

.trust-bar__stats {
  display: flex;
  justify-content: center;
  gap: 3rem;
  flex-wrap: wrap;
}

.trust-bar__stat {
  text-align: center;
  min-width: 100px;
}

.trust-bar__number {
  display: block;
  font-size: 2rem;
  font-weight: 700;
  color: var(--bp-green);
  line-height: 1.2;
  margin-bottom: 0.25rem;
}

.trust-bar__label {
  display: block;
  font-size: 0.85rem;
  color: var(--bp-text-light);
}

@media (max-width: 749px) {
  .trust-bar__stats {
    display: grid;
    grid-template-columns: repeat(2, 1fr);
    gap: 1.5rem;
  }
  .trust-bar__number {
    font-size: 1.5rem;
  }
}

/* --- Service Grid --- */
.service-grid {
  background-color: var(--bp-white);
}

.service-grid__header {
  text-align: center;
  margin-bottom: 2.5rem;
}

.service-grid__heading {
  font-size: clamp(1.5rem, 4vw, 2.25rem);
  font-weight: 700;
  color: var(--bp-text);
  margin: 0 0 0.5rem;
}

.service-grid__subheading {
  font-size: clamp(0.9rem, 2vw, 1.05rem);
  color: var(--bp-text-light);
  max-width: 600px;
  margin: 0 auto;
  line-height: 1.6;
}

.service-grid__grid {
  display: grid;
  grid-template-columns: 1fr;
  gap: 1.5rem;
}

.service-grid__card {
  background: var(--bp-white);
  border: 1px solid var(--bp-border);
  border-radius: 12px;
  padding: 2rem 1.5rem;
  text-align: center;
  box-shadow: 0 2px 8px rgba(0, 0, 0, 0.06);
  transition: transform 0.3s ease, box-shadow 0.3s ease;
}

.service-grid__card:hover {
  transform: translateY(-4px);
  box-shadow: 0 8px 24px rgba(0, 0, 0, 0.1);
}

.service-grid__icon {
  width: 64px;
  height: 64px;
  margin: 0 auto 1rem;
  display: flex;
  align-items: center;
  justify-content: center;
  background-color: rgba(26, 77, 46, 0.08);
  border-radius: 50%;
  color: var(--bp-green);
}

.service-grid__icon svg {
  width: 32px;
  height: 32px;
}

.service-grid__title {
  font-size: 1.1rem;
  font-weight: 600;
  color: var(--bp-text);
  margin: 0 0 0.5rem;
}

.service-grid__description {
  font-size: 0.875rem;
  color: var(--bp-text-light);
  line-height: 1.6;
  margin: 0 0 1rem;
}

.service-grid__price {
  font-size: 1.25rem;
  font-weight: 700;
  color: var(--bp-orange);
  margin: 0 0 1rem;
}

.service-grid__link {
  color: var(--bp-green);
  font-weight: 600;
  font-size: 0.9rem;
  text-decoration: none;
  transition: color 0.3s ease;
}

.service-grid__link:hover {
  color: var(--bp-green-light);
}

@media (min-width: 750px) {
  .service-grid__grid {
    grid-template-columns: repeat(2, 1fr);
  }
}

@media (min-width: 990px) {
  .service-grid__grid {
    grid-template-columns: repeat(3, 1fr);
    gap: 2rem;
  }
}

/* --- Process Timeline --- */
.process-timeline__header {
  text-align: center;
  margin-bottom: 2.5rem;
}

.process-timeline__heading {
  font-size: clamp(1.5rem, 4vw, 2.25rem);
  font-weight: 700;
  color: var(--bp-text);
  margin: 0 0 0.5rem;
}

.process-timeline__subheading {
  font-size: clamp(0.9rem, 2vw, 1.05rem);
  color: var(--bp-text-light);
  max-width: 600px;
  margin: 0 auto;
  line-height: 1.6;
}

.process-timeline__steps {
  display: flex;
  flex-direction: column;
  gap: 2rem;
  position: relative;
  padding-left: 2.5rem;
}

/* Vertical line (mobile) */
.process-timeline__steps::before {
  content: '';
  position: absolute;
  left: 15px;
  top: 0;
  bottom: 0;
  width: 2px;
  background-color: var(--bp-border);
}

.process-timeline__step {
  position: relative;
}

.process-timeline__number {
  position: absolute;
  left: -2.5rem;
  top: 0;
  width: 32px;
  height: 32px;
  background-color: var(--bp-green);
  color: var(--bp-white);
  border-radius: 50%;
  display: flex;
  align-items: center;
  justify-content: center;
  font-size: 0.85rem;
  font-weight: 700;
  z-index: 1;
}

.process-timeline__connector {
  display: none; /* handled by ::before on mobile */
}

.process-timeline__title {
  font-size: 1rem;
  font-weight: 600;
  color: var(--bp-text);
  margin: 0 0 0.25rem;
}

.process-timeline__description {
  font-size: 0.875rem;
  color: var(--bp-text-light);
  line-height: 1.5;
  margin: 0;
}

@media (min-width: 990px) {
  .process-timeline__steps {
    flex-direction: row;
    padding-left: 0;
    gap: 0;
    justify-content: space-between;
  }

  .process-timeline__steps::before {
    left: 16px;
    right: 16px;
    top: 16px;
    bottom: auto;
    width: auto;
    height: 2px;
  }

  .process-timeline__step {
    flex: 1;
    text-align: center;
    padding: 3.5rem 1rem 0;
  }

  .process-timeline__number {
    left: 50%;
    top: 0;
    transform: translateX(-50%);
  }
}

/* --- Buttons (general) --- */
.btn-primary {
  display: inline-flex;
  align-items: center;
  justify-content: center;
  font-family: 'Poppins', sans-serif;
  font-size: 0.95rem;
  font-weight: 600;
  padding: 0 2rem;
  height: 54px;
  border: none;
  border-radius: 12px;
  cursor: pointer;
  text-decoration: none;
  background-color: var(--bp-orange);
  color: var(--bp-white);
  transition: background-color 0.3s ease;
}
.btn-primary:hover {
  background-color: var(--bp-orange-hover);
  color: var(--bp-white);
}

.btn-secondary {
  display: inline-flex;
  align-items: center;
  justify-content: center;
  font-family: 'Poppins', sans-serif;
  font-size: 0.95rem;
  font-weight: 600;
  padding: 0 2rem;
  height: 54px;
  border: 2px solid var(--bp-green);
  border-radius: 12px;
  cursor: pointer;
  text-decoration: none;
  background-color: transparent;
  color: var(--bp-green);
  transition: all 0.3s ease;
}
.btn-secondary:hover {
  background-color: var(--bp-green);
  color: var(--bp-white);
}

/* Dawn button override for product pages */
.product-form__submit.button {
  background-color: var(--bp-orange);
  color: var(--bp-white);
  font-family: 'Poppins', sans-serif;
  font-weight: 600;
  border-radius: 12px;
  min-height: 54px;
}
.product-form__submit.button:hover {
  background-color: var(--bp-orange-hover);
}

/* Dawn buttons general override */
.button:not(.shopify-challenge__button) {
  border-radius: 12px;
  font-family: 'Poppins', sans-serif;
}

/* --- Footer (Dawn overrides) --- */
.section-footer .footer {
  background-color: var(--bp-green) !important;
  color: var(--bp-white);
}
.section-footer .footer a {
  color: rgba(255, 255, 255, 0.8);
  text-decoration: none;
}
.section-footer .footer a:hover {
  color: var(--bp-orange);
}
.section-footer .footer__title {
  color: var(--bp-white);
  font-weight: 600;
}
.section-footer .footer__content-bottom {
  border-top: 1px solid rgba(255, 255, 255, 0.15);
}
.section-footer .copyright__content,
.section-footer .footer__content-bottom-wrapper a {
  color: rgba(255, 255, 255, 0.5);
}
.section-footer .footer__list-social .list-social__link {
  color: var(--bp-white);
}
.section-footer .footer__list-social .list-social__link:hover {
  color: var(--bp-orange);
}
.section-footer .newsletter-form__field-wrapper .field__input {
  border-radius: 8px;
}
.section-footer .newsletter-form__button {
  background-color: var(--bp-orange);
  border-radius: 8px;
}

/* --- Announcement Bar (blend with header) --- */
.shopify-section-group-header-group .announcement-bar-section,
.shopify-section-group-header-group .utility-bar {
  background-color: #0D2617 !important;
  border: none !important;
}
.announcement-bar {
  font-family: 'Poppins', sans-serif;
}
.announcement-bar__message,
.announcement-bar__message span {
  color: rgba(255, 255, 255, 0.6) !important;
  font-size: 0.75rem !important;
  font-weight: 400 !important;
  letter-spacing: 0.03em;
}
.announcement-bar__link {
  color: rgba(255, 255, 255, 0.6) !important;
  text-decoration: none !important;
}
/* Remove line between announcement bar and header */
.shopify-section-group-header-group .utility-bar + .section-header,
.section-header .header-wrapper {
  border-top: none !important;
}
.header-wrapper--border-bottom {
  border-bottom: none !important;
}

/* --- Logo on dark header --- */
.header__heading-logo-wrapper {
  display: flex;
  align-items: center;
}
.header__heading-logo {
  max-height: 60px;
  width: auto;
  /* Make green logo visible on dark green header */
  filter: brightness(0) invert(1);
}
/* Also handle text fallback if no logo uploaded */
.section-header .header__heading-link .h2,
.section-header .header__heading-link span {
  color: var(--bp-white) !important;
  font-family: 'Poppins', sans-serif;
  font-weight: 700;
  font-size: 1.25rem;
  letter-spacing: -0.01em;
}

/* --- Scroll Reveal --- */
.reveal-on-scroll {
  opacity: 0;
  transform: translateY(20px);
  transition: opacity 0.6s ease, transform 0.6s ease;
}
.reveal-on-scroll.is-visible {
  opacity: 1;
  transform: none;
}
@media (prefers-reduced-motion: reduce) {
  .reveal-on-scroll {
    opacity: 1;
    transform: none;
    transition: none;
  }
}

/* --- Utilities --- */
.text-accent { color: var(--bp-orange); }
.text-green { color: var(--bp-green); }
.section-padding { padding: 40px 1.25rem; }
@media (min-width: 750px) { .section-padding { padding: 50px 2rem; } }
@media (min-width: 990px) { .section-padding { padding: 60px 3rem; } }

