{%- liquid
  assign overlay_opacity = section.settings.overlay_opacity | divided_by: 100.0
-%}

<section class="hero">
  <div class="hero__pattern" aria-hidden="true"></div>
  <div class="container">
    <div class="hero__inner">
      <div class="hero__text">
        <span class="hero__eyebrow">{{ section.settings.eyebrow }}</span>
        <h1>{{ section.settings.heading_line_1 }} <em>{{ section.settings.heading_line_2 }}</em> {{ section.settings.heading_line_3 }}</h1>
        <p class="hero__sub">{{ section.settings.subheading }}</p>

        <div class="hero__cta">
          {%- if section.settings.button_1_label != blank -%}
            <a href="{{ section.settings.button_1_link }}" class="btn btn--primary btn--lg">{{ section.settings.button_1_label }}</a>
          {%- endif -%}
          {%- if section.settings.button_2_label != blank -%}
            <a href="{{ section.settings.button_2_link }}" class="btn btn--outline-white btn--lg">{{ section.settings.button_2_label }}</a>
          {%- endif -%}
        </div>

        <div class="hero__stats">
          {%- for block in section.blocks -%}
            {%- if block.type == 'stat' -%}
              <div class="hero__stat" {{ block.shopify_attributes }}>
                <div class="num">{{ block.settings.number }}</div>
                <div class="lbl">{{ block.settings.label }}</div>
              </div>
            {%- endif -%}
          {%- endfor -%}
        </div>
      </div>

      <div class="hero__image-wrap" aria-hidden="true">
        {%- if section.settings.background_image != blank -%}
          <img
            src="{{ section.settings.background_image | image_url: width: 800 }}"
            srcset="{{ section.settings.background_image | image_url: width: 600 }} 600w, {{ section.settings.background_image | image_url: width: 800 }} 800w"
            alt="{{ section.settings.background_image.alt | default: 'Professional property services' | escape }}"
            width="800"
            height="600"
            loading="eager"
          >
        {%- else -%}
          <div class="hero__image-placeholder"></div>
        {%- endif -%}

        {%- if section.settings.badge_title != blank -%}
          <div class="hero__badge">
            <svg viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" aria-hidden="true"><polyline points="20 6 9 17 4 12"></polyline></svg>
            <div>
              <strong>{{ section.settings.badge_title }}</strong>
              <span>{{ section.settings.badge_subtitle }}</span>
            </div>
          </div>
        {%- endif -%}
      </div>
    </div>
  </div>
</section>

{% schema %}
{
  "name": "Hero Banner",
  "tag": "div",
  "class": "section-hero-banner",
  "settings": [
    {
      "type": "text",
