    },
    {
      "type": "text",
      "id": "heading_line_3",
      "label": "Heading line 3",
      "default": "You Can Trust"
    },
    {
      "type": "textarea",
      "id": "subheading",
      "label": "Subheading",
      "default": "From legal packs to photography, surveys to tenancy agreements — everything you need to buy, sell or let property in the UK."
    },
    {
      "type": "image_picker",
      "id": "background_image",
      "label": "Hero image"
    },
    {
      "type": "range",
      "id": "overlay_opacity",
      "label": "Overlay opacity",
      "min": 0,
      "max": 100,
      "step": 5,
      "default": 65,
      "unit": "%"
    },
    {
      "type": "text",
      "id": "button_1_label",
      "label": "Button 1 label",
      "default": "View All Services"
    },
    {
      "type": "url",
      "id": "button_1_link",
      "label": "Button 1 link"
    },
    {
      "type": "text",
      "id": "button_2_label",
      "label": "Button 2 label",
      "default": "Learn More"
    },
    {
      "type": "url",
      "id": "button_2_link",
      "label": "Button 2 link"
    },
    {
      "type": "text",
      "id": "badge_title",
      "label": "Badge title",
      "default": "RICS Regulated"
    },
    {
      "type": "text",
      "id": "badge_subtitle",
      "label": "Badge subtitle",
      "default": "UK Property Experts"
    }
  ],
  "blocks": [
    {
      "type": "stat",
      "name": "Stat",
      "settings": [
        {
          "type": "text",
          "id": "number",
          "label": "Number",
          "default": "5,000+"
        },
        {
          "type": "text",
          "id": "label",
          "label": "Label",
          "default": "Happy Clients"
        }
      ]
    }
  ],
  "presets": [
    {
      "name": "Hero Banner",
      "blocks": [
        { "type": "stat", "settings": { "number": "5,000+", "label": "Happy Clients" } },
        { "type": "stat", "settings": { "number": "8", "label": "Services Offered" } },
        { "type": "stat", "settings": { "number": "98%", "label": "Satisfaction" } }
      ]
    }
  ]
}
{% endschema %}

