      "label": "Button 2 link"
    },
    {
      "type": "text",
      "id": "badge_title",
      "label": "Badge title",
      "default": "RICS Regulated"
    },
    {
      "type": "text",
      "id": "badge_subtitle",
      "label": "Badge subtitle",
      "default": "UK Property Experts"
    }
  ],
  "blocks": [
    {
      "type": "stat",
      "name": "Stat",
      "settings": [
        {
          "type": "text",
