          "default": "5,000+"
        },
        {
          "type": "text",
          "id": "label",
          "label": "Label",
          "default": "Happy Clients"
        }
      ]
    }
  ],
  "presets": [
    {
      "name": "Hero Banner",
      "blocks": [
        { "type": "stat", "settings": { "number": "5,000+", "label": "Happy Clients" } },
        { "type": "stat", "settings": { "number": "8", "label": "Services Offered" } },
        { "type": "stat", "settings": { "number": "98%", "label": "Satisfaction" } }
      ]
    }
  ]
}
{% endschema %}

