/* ==========================================================================
   Buy Property Services — Custom Theme Styles
   Inspired by the clean, professional property services design
   ========================================================================== */
@import url('https://fonts.googleapis.com/css2?family=Poppins:wght@400;500;600;700&display=swap');

/* --- Brand Variables --- */
:root {
  --bp-green: #1A4D2E;
  --bp-green-dark: #0D2617;
  --bp-green-light: #2D7A4A;
  --bp-orange: #E8922A;
  --bp-orange-hover: #D4872E;
  --bp-olive: #8FB339;
  --bp-cream: #F5F0E1;
  --bp-tan: #C4B699;
  --bp-text: #1A1A1A;
  --bp-text-light: #555555;
  --bp-white: #FFFFFF;
  --bp-border: #E5E5E5;
  --bp-bg-light: #f8f9fa;
  --bp-radius: 12px;
}

/* --- Typography --- */
body, h1, h2, h3, h4, h5, h6 {
  font-family: 'Poppins', -apple-system, BlinkMacSystemFont, 'Segoe UI', Roboto, sans-serif;
}
body {
  color: var(--bp-text);
  -webkit-font-smoothing: antialiased;
  margin: 0;
}
h1, h2, h3, h4, h5, h6 {
  color: var(--bp-text);
  font-weight: 700;
  line-height: 1.2;
}

/* --- Layout --- */
.container {
  max-width: 1200px;
  margin: 0 auto;
  padding: 0 24px;
}
.section {
  padding: 80px 0;
}
@media (max-width: 749px) {
  .section { padding: 48px 0; }
}

/* --- Section Headers --- */
.section-header {
  text-align: center;
  margin-bottom: 48px;
  background: none;
  position: static;
}
.section-header h2 {
  font-size: clamp(1.75rem, 4vw, 2.5rem);
  margin: 0 0 12px;
}
.section-header p {
  color: var(--bp-text-light);
  font-size: 1.05rem;
  max-width: 600px;
  margin: 0 auto;
  line-height: 1.6;
}
.eyebrow {
  display: inline-block;
  font-size: 0.8rem;
  font-weight: 600;
  text-transform: uppercase;
  letter-spacing: 0.1em;
  color: var(--bp-orange);
  margin-bottom: 8px;
}

/* --- Buttons --- */
.btn {
  display: inline-flex;
  align-items: center;
  justify-content: center;
  font-family: 'Poppins', sans-serif;
  font-weight: 600;
  border-radius: var(--bp-radius);
  cursor: pointer;
  text-decoration: none;
  transition: all 0.25s ease;
  border: 2px solid transparent;
  line-height: 1;
}
.btn--sm {
  font-size: 0.85rem;
  padding: 8px 20px;
  height: 38px;
}
.btn--lg {
  font-size: 0.95rem;
  padding: 14px 32px;
  height: 52px;
}
.btn--primary {
  background-color: var(--bp-orange);
  color: var(--bp-white);
  border-color: var(--bp-orange);
}
.btn--primary:hover {
  background-color: var(--bp-orange-hover);
  border-color: var(--bp-orange-hover);
  color: var(--bp-white);
}
.btn--secondary {
  background-color: var(--bp-white);
  color: var(--bp-green);
  border-color: var(--bp-green);
}
.btn--secondary:hover {
  background-color: var(--bp-green);
  color: var(--bp-white);
}
.btn--outline-white {
  background: transparent;
  color: var(--bp-white);
  border-color: rgba(255,255,255,0.4);
}
.btn--outline-white:hover {
  background: var(--bp-white);
  color: var(--bp-green);
  border-color: var(--bp-white);
}

/* ==========================================================================
   HERO
   ========================================================================== */
.hero {
  position: relative;
  background: linear-gradient(135deg, #0f3d1f 0%, #1A4D2E 40%, #1e5c35 100%);
  overflow: hidden;
  padding: 80px 0 60px;
}
.hero__pattern {
  position: absolute;
  inset: 0;
  background-image:
    radial-gradient(circle at 20% 50%, rgba(255,255,255,0.03) 0%, transparent 50%),
    radial-gradient(circle at 80% 20%, rgba(255,255,255,0.04) 0%, transparent 40%);
}
.hero__inner {
  display: grid;
  grid-template-columns: 1fr 1fr;
  gap: 60px;
  align-items: center;
  position: relative;
  z-index: 1;
}
.hero__text {
  color: var(--bp-white);
}
.hero__eyebrow {
  display: inline-block;
  font-size: 0.8rem;
  font-weight: 600;
  text-transform: uppercase;
  letter-spacing: 0.12em;
  color: var(--bp-orange);
  margin-bottom: 16px;
}
.hero__text h1 {
  font-size: clamp(2rem, 5vw, 3.25rem);
  font-weight: 700;
  color: var(--bp-white);
  margin: 0 0 20px;
  line-height: 1.15;
}
.hero__text h1 em {
  font-style: normal;
  color: var(--bp-orange);
}
.hero__sub {
  font-size: 1.05rem;
  color: rgba(255,255,255,0.8);
  line-height: 1.7;
  margin: 0 0 32px;
  max-width: 520px;
}
.hero__cta {
  display: flex;
  gap: 12px;
  flex-wrap: wrap;
  margin-bottom: 48px;
}
.hero__stats {
  display: flex;
  gap: 40px;
}
.hero__stat {
  text-align: left;
}
.hero__stat .num {
  font-size: 1.75rem;
  font-weight: 700;
  color: var(--bp-white);
  line-height: 1.2;
}
.hero__stat .lbl {
  font-size: 0.8rem;
  color: rgba(255,255,255,0.6);
  margin-top: 2px;
}

/* Hero image */
.hero__image-wrap {
  position: relative;
}
.hero__image-wrap img {
  width: 100%;
  height: auto;
  border-radius: 16px;
  object-fit: cover;
  display: block;
}
.hero__image-placeholder {
  width: 100%;
  aspect-ratio: 4/3;
  background: rgba(255,255,255,0.08);
  border-radius: 16px;
}
.hero__badge {
  position: absolute;
  bottom: -16px;
  left: 24px;
  background: var(--bp-white);
  border-radius: var(--bp-radius);
  padding: 12px 20px;
  display: flex;
  align-items: center;
  gap: 10px;
  box-shadow: 0 8px 30px rgba(0,0,0,0.15);
}
.hero__badge svg {
  width: 24px;
  height: 24px;
  color: var(--bp-green);
  flex-shrink: 0;
}
.hero__badge strong {
  display: block;
  font-size: 0.85rem;
  font-weight: 700;
  color: var(--bp-text);
}
.hero__badge span {
  display: block;
  font-size: 0.75rem;
  color: var(--bp-text-light);
}

@media (max-width: 989px) {
  .hero { padding: 48px 0 40px; }
  .hero__inner {
    grid-template-columns: 1fr;
    gap: 40px;
    text-align: center;
  }
  .hero__sub { margin-left: auto; margin-right: auto; }
  .hero__cta { justify-content: center; }
  .hero__stats { justify-content: center; gap: 32px; }
  .hero__stat { text-align: center; }
  .hero__image-wrap { max-width: 500px; margin: 0 auto; }
  .hero__badge { left: 50%; transform: translateX(-50%); }
}
@media (max-width: 479px) {
  .hero__stats { gap: 20px; }
  .hero__stat .num { font-size: 1.35rem; }
  .hero__cta { flex-direction: column; align-items: center; }
  .hero__cta .btn { width: 100%; max-width: 280px; }
}

/* ==========================================================================
   SERVICES GRID
   ========================================================================== */
.services-section {
  background: var(--bp-bg-light);
}
.services-grid {
  display: grid;
  grid-template-columns: repeat(4, 1fr);
  gap: 24px;
}
.service-card {
  background: var(--bp-white);
  border: 1px solid var(--bp-border);
  border-radius: var(--bp-radius);
  padding: 28px 24px;
  display: flex;
  flex-direction: column;
  transition: transform 0.25s ease, box-shadow 0.25s ease;
}
.service-card:hover {
  transform: translateY(-4px);
  box-shadow: 0 12px 32px rgba(0,0,0,0.08);
}
.service-card__icon {
  width: 48px;
  height: 48px;
  display: flex;
  align-items: center;
  justify-content: center;
  background: rgba(26, 77, 46, 0.08);
  border-radius: 10px;
  margin-bottom: 16px;
  color: var(--bp-green);
}
.service-card__icon svg {
  width: 24px;
  height: 24px;
}
.service-card__title {
  font-size: 1rem;
  font-weight: 600;
  color: var(--bp-text);
  margin: 0 0 8px;
}
.service-card__desc {
  font-size: 0.875rem;
  color: var(--bp-text-light);
  line-height: 1.6;
  margin: 0;
  flex: 1;
}
.service-card__footer {
  display: flex;
  align-items: center;
  justify-content: space-between;
  margin-top: 20px;
  padding-top: 16px;
  border-top: 1px solid var(--bp-border);
}
.service-card__price {
  font-size: 1rem;
  font-weight: 700;
  color: var(--bp-green);
}
.service-card__price small {
  display: block;
  font-size: 0.75rem;
  font-weight: 400;
  color: var(--bp-text-light);
}

@media (max-width: 989px) {
  .services-grid { grid-template-columns: repeat(2, 1fr); }
}
@media (max-width: 579px) {
  .services-grid { grid-template-columns: 1fr; }
}

/* ==========================================================================
   WHY CHOOSE US
   ========================================================================== */
.why-section {
  background: var(--bp-white);
}
.why-grid {
  display: grid;
  grid-template-columns: 1fr 1fr;
  gap: 60px;
  align-items: start;
}
.why-features {
  display: flex;
  flex-direction: column;
  gap: 28px;
}
.why-feature {
  display: flex;
  gap: 16px;
  align-items: flex-start;
}
.why-feature__icon {
  width: 44px;
  height: 44px;
  min-width: 44px;
  display: flex;
  align-items: center;
  justify-content: center;
  background: rgba(26, 77, 46, 0.08);
  border-radius: 10px;
  color: var(--bp-green);
}
.why-feature__icon svg {
  width: 22px;
  height: 22px;
}
.why-feature__text h4 {
  font-size: 1rem;
  font-weight: 600;
  color: var(--bp-text);
  margin: 0 0 4px;
}
.why-feature__text p {
  font-size: 0.875rem;
  color: var(--bp-text-light);
  line-height: 1.6;
  margin: 0;
}

/* Stats visual */
.why-visual {
  display: grid;
  grid-template-columns: 1fr 1fr;
  gap: 16px;
}
.why-stat-card {
  background: var(--bp-bg-light);
  border-radius: var(--bp-radius);
  padding: 28px 24px;
  text-align: center;
}
.why-stat-card.full {
  grid-column: 1 / -1;
}
.why-stat-card .num {
  font-size: 2rem;
  font-weight: 700;
  color: var(--bp-green);
  line-height: 1.2;
}
.why-stat-card .lbl {
  font-size: 0.85rem;
  color: var(--bp-text-light);
  margin-top: 4px;
}

@media (max-width: 989px) {
  .why-grid {
    grid-template-columns: 1fr;
    gap: 40px;
  }
  .why-visual {
    max-width: 400px;
  }
}

/* ==========================================================================
   TESTIMONIALS
   ========================================================================== */
.testimonials-section {
  background: var(--bp-bg-light);
}
.testimonials-grid {
  display: grid;
  grid-template-columns: repeat(3, 1fr);
  gap: 24px;
}
.testimonial-card {
  background: var(--bp-white);
  border: 1px solid var(--bp-border);
  border-radius: var(--bp-radius);
  padding: 28px 24px;
}
.testimonial-stars {
  color: #f59e0b;
  font-size: 1.1rem;
  margin-bottom: 16px;
  letter-spacing: 2px;
}
.testimonial-text {
  font-size: 0.925rem;
  color: var(--bp-text);
  line-height: 1.7;
  margin: 0 0 20px;
  font-style: italic;
}
.testimonial-author {
  display: flex;
  align-items: center;
  gap: 12px;
}
.testimonial-avatar {
  width: 40px;
  height: 40px;
  border-radius: 50%;
  background: var(--bp-green);
  color: var(--bp-white);
  display: flex;
  align-items: center;
  justify-content: center;
  font-weight: 700;
  font-size: 0.9rem;
  flex-shrink: 0;
}
.testimonial-name {
  font-size: 0.9rem;
  font-weight: 600;
  color: var(--bp-text);
}
.testimonial-role {
  font-size: 0.8rem;
  color: var(--bp-text-light);
}

@media (max-width: 989px) {
  .testimonials-grid { grid-template-columns: 1fr; max-width: 560px; margin: 0 auto; }
}

/* ==========================================================================
   CTA BAND
   ========================================================================== */
.cta-band {
  background: linear-gradient(135deg, #0f3d1f 0%, #1A4D2E 100%);
  padding: 64px 0;
  text-align: center;
}
.cta-band h2 {
  font-size: clamp(1.5rem, 4vw, 2.25rem);
  color: var(--bp-white);
  margin: 0 0 12px;
}
.cta-band p {
  color: rgba(255,255,255,0.75);
  font-size: 1.05rem;
  margin: 0 0 32px;
  max-width: 560px;
  margin-left: auto;
  margin-right: auto;
  line-height: 1.6;
}

/* ==========================================================================
   ANNOUNCEMENT BAR (Dawn override — blend with header)
   ========================================================================== */
.shopify-section-group-header-group .announcement-bar-section,
.shopify-section-group-header-group .utility-bar,
.shopify-section-group-header-group .announcement-bar__wrapper,
.shopify-section-group-header-group .color-scheme-4 {
  background-color: var(--bp-green-dark) !important;
  border: none !important;
}
.announcement-bar {
  font-family: 'Poppins', sans-serif;
  border: none !important;
  padding: 6px 0 !important;
  min-height: unset !important;
}
.announcement-bar__message,
.announcement-bar__message span,
.announcement-bar__message p {
  color: rgba(255,255,255,0.65) !important;
  font-size: 0.75rem !important;
  font-weight: 400 !important;
  letter-spacing: 0.03em;
  margin: 0;
}
.announcement-bar__link {
  color: rgba(255,255,255,0.65) !important;
  text-decoration: none !important;
}

/* ==========================================================================
   HEADER (Dawn overrides)
   ========================================================================== */
.section-header,
.header-wrapper {
  background-color: var(--bp-green) !important;
  border: none !important;
}
/* Kill ALL borders between announcement and header */
.shopify-section-group-header-group > *,
.header-wrapper--border-bottom {
  border-top: none !important;
  border-bottom: none !important;
}
.section-header a,
.section-header .header__heading-link,
.section-header .header__menu-item,
.section-header .list-menu__item--link {
  color: var(--bp-white) !important;
  text-decoration: none;
}
.section-header .header__menu-item:hover,
.section-header .list-menu__item--link:hover {
  color: var(--bp-orange) !important;
}
.section-header .header__icon,
.section-header .header__icon .icon {
  color: var(--bp-white) !important;
  fill: var(--bp-white);
}
.section-header .header__icon:hover,
.section-header .header__icon:hover .icon {
  color: var(--bp-orange) !important;
}
.section-header .cart-count-bubble {
  background-color: var(--bp-orange);
  color: var(--bp-white);
}
.header__inline-menu .header__menu-item {
  color: var(--bp-white);
}

/* Mobile menu drawer */
.menu-drawer {
  background-color: var(--bp-green) !important;
}
.menu-drawer a,
.menu-drawer .menu-drawer__menu-item {
  color: var(--bp-white) !important;
  font-family: 'Poppins', sans-serif;
}
.menu-drawer a:hover {
  color: var(--bp-orange) !important;
}
.menu-drawer__close-button .icon {
  color: var(--bp-white);
}

/* Logo */
.header__heading-logo-wrapper {
  display: flex;
  align-items: center;
}
.header__heading-logo {
  max-height: 60px;
  width: auto;
  filter: brightness(0) invert(1);
}
.section-header .header__heading-link .h2,
.section-header .header__heading-link span {
  color: var(--bp-white) !important;
  font-family: 'Poppins', sans-serif;
  font-weight: 700;
  font-size: 1.25rem;
}

/* ==========================================================================
   FOOTER (Dawn overrides)
   ========================================================================== */
.section-footer .footer {
  background-color: var(--bp-green) !important;
  color: var(--bp-white);
}
.section-footer .footer a {
  color: rgba(255,255,255,0.8);
  text-decoration: none;
}
.section-footer .footer a:hover {
  color: var(--bp-orange);
}
.section-footer .footer__content-bottom {
  border-top: 1px solid rgba(255,255,255,0.15);
}
.section-footer .copyright__content,
.section-footer .footer__content-bottom-wrapper a {
  color: rgba(255,255,255,0.5);
}

/* ==========================================================================
   DAWN BUTTON OVERRIDES
   ========================================================================== */
.button:not(.shopify-challenge__button) {
  border-radius: var(--bp-radius);
  font-family: 'Poppins', sans-serif;
}
.product-form__submit.button {
  background-color: var(--bp-orange);
  color: var(--bp-white);
  font-family: 'Poppins', sans-serif;
  font-weight: 600;
  border-radius: var(--bp-radius);
  min-height: 54px;
}
.product-form__submit.button:hover {
  background-color: var(--bp-orange-hover);
}

/* ==========================================================================
   UTILITIES
   ========================================================================== */
.reveal-on-scroll {
  opacity: 0;
  transform: translateY(20px);
  transition: opacity 0.6s ease, transform 0.6s ease;
}
.reveal-on-scroll.is-visible {
  opacity: 1;
  transform: none;
}
@media (prefers-reduced-motion: reduce) {
  .reveal-on-scroll {
    opacity: 1;
    transform: none;
    transition: none;
  }
}

