/* ==========================================================================
   Buy Property Services — Custom Theme Styles
   Inspired by the clean, professional property services design
   ========================================================================== */
@import url('https://fonts.googleapis.com/css2?family=Poppins:wght@400;500;600;700&display=swap');

/* --- Brand Variables --- */
:root {
  --bp-green: #1A4D2E;
  --bp-green-dark: #0D2617;
  --bp-green-light: #2D7A4A;
  --bp-orange: #E8922A;
  --bp-orange-hover: #D4872E;
  --bp-olive: #8FB339;
  --bp-cream: #F5F0E1;
  --bp-tan: #C4B699;
  --bp-text: #1A1A1A;
  --bp-text-light: #555555;
  --bp-white: #FFFFFF;
  --bp-border: #E5E5E5;
  --bp-bg-light: #f8f9fa;
  --bp-radius: 12px;
}

/* --- Typography --- */
body, h1, h2, h3, h4, h5, h6 {
  font-family: 'Poppins', -apple-system, BlinkMacSystemFont, 'Segoe UI', Roboto, sans-serif;
}
body {
  color: var(--bp-text);
  -webkit-font-smoothing: antialiased;
  margin: 0;
}
h1, h2, h3, h4, h5, h6 {
  color: var(--bp-text);
  font-weight: 700;
  line-height: 1.2;
}

/* --- Layout --- */
.section {
  padding: 80px 0;
}
@media (max-width: 749px) {
  .section { padding: 48px 0; }
}

/* --- Section Headers (bp- prefix to avoid Dawn conflict) --- */
.bp-section-header {
  text-align: center;
  margin-bottom: 48px;
}
.bp-section-header h2 {
  font-size: clamp(1.75rem, 4vw, 2.5rem);
  margin: 0 0 12px;
}
.bp-section-header p {
  color: var(--bp-text-light);
  font-size: 1.05rem;
  max-width: 600px;
  margin: 0 auto;
  line-height: 1.6;
}
.eyebrow {
  display: inline-block;
  font-size: 0.8rem;
  font-weight: 600;
  text-transform: uppercase;
  letter-spacing: 0.1em;
  color: var(--bp-orange);
  margin-bottom: 8px;
}

/* --- Buttons --- */
.btn {
  display: inline-flex;
  align-items: center;
  justify-content: center;
  font-family: 'Poppins', sans-serif;
  font-weight: 600;

