  text-transform: uppercase;
  letter-spacing: 0.12em;
  color: var(--bp-orange);
  margin-bottom: 16px;
}
.hero__text h1 {
  font-size: clamp(2rem, 5vw, 3.25rem);
  font-weight: 700;
  color: var(--bp-white);
  margin: 0 0 20px;
  line-height: 1.15;
}
.hero__text h1 em {
  font-style: normal;
  color: var(--bp-orange);
}
.hero__sub {
  font-size: 1.05rem;
  color: rgba(255,255,255,0.8);
  line-height: 1.7;
  margin: 0 0 32px;
  max-width: 520px;
}
.hero__cta {
  display: flex;
  gap: 12px;
  flex-wrap: wrap;
  margin-bottom: 48px;
}
.hero__stats {
  display: flex;
  gap: 40px;
}
